      cutUpHelp: { example1: "the doctor waits", example2: "by the window", example3: "listening", sourceTitle: "Source", sourceBody: "Start with something you’ve already written — a stuck verse, an old page, anything. Paste it in or pull a page from your Lyrics Pad. You’re not starting from scratch; you’re remixing your own words.", sourceText: "the doctor waits, by the window\nlistening to the rain come down\ncounting all the empty hours", sourceResult: "something to cut apart", pasteTitle: "Paste anything", pasteBody: "A draft, a fragment, a whole song.", pullTitle: "Or pull a page", pullBody: "Choose from your Lyrics Pad.", copyTitle: "Not precious", copyBody: "This is a copy — the original stays put.", cutTitle: "Cut", cutBody: "Cut the lyric into moveable pieces — right where you want. It starts cut into phrases; a scissor seam sits between every word. Tap a seam to cut or join there, or press and slide across a few words to bind them into one unit.", cutResult: "pieces you can rearrange", seamTitle: "Tap a seam", seamBody: "Cut or join between any two words.", slideTitle: "Press & slide", slideBody: "Drag across words to bind them into one piece.", resetTitle: "Reset cuts", resetBody: "Snap back to the natural phrase breaks.", arrangeTitle: "Arrange", arrangeBody: "Now shuffle the strips like cut-outs on a table. Drag them into a new order, shuffle for happy accidents, and lock the lines that already feel right so they stay put.", arrangeResult: "an order you’d never plan", shuffleTitle: "Shuffle", shuffleBody: "Reorder the unlocked strips at random.", lockTitle: "Lock", lockBody: "Pin a strip so shuffles skip it.", restoreTitle: "Remove & restore", restoreBody: "Set strips aside, bring them back anytime.", draftTitle: "Draft", draftBody: "Your arrangement becomes a draft. Now it’s yours to finish — add words between strips, fix awkward seams, cut what doesn’t sing. Save it to your Lyrics Pad when a new direction shows up.", fromShuffled: "From shuffled strips", draftExample: "listening\nthe doctor waits\nby the window", worthKeeping: "…to a line worth keeping", revisedExample: "Listening for the doctor\nwho waits by the window all night", credit: "after Jeff Tweedy’s cut-up method, How to Write One Song (2020)", composeTitle: "Compose", composeBody: "Shuffle the pieces into varied-length fragment lines — short, mixed, or long.", boardTitle: "Board order", boardBody: "Or rebuild plainly, one piece per line.", saveTitle: "Save", saveBody: "Send the draft to your Lyrics Pad." },
