      magpieHelp: { pageTitle: "העמוד", pageBody: "Magpie פותח ספר אמיתי בעמוד אקראי. זמזמו לעצמכם מנגינה, ואז לחצו על המילים והביטויים שנשמעים טוב מולה — לא אלה שמסתדרים בהיגיון, אלא אלה שמצלצלים נכון. לחצו על רצף מילים כדי לשמור אותן יחד; לחצו שוב כדי לשחרר מילה.", catchesEar: "לחצו על מה שתופס את האוזן", pageExampleBefore: "…אור ", pageExampleMark1: "הנמל", pageExampleMiddle: " היה נמוך, ואיש לא ", pageExampleMark2: "ענה", pageExampleAfter: "…", intoPile: "…אל הערימה שלך", pileExample: "אור הנמל · ענה", newPageTitle: "עמוד חדש", newPageBody: "אותו ספר, עמוד אחר.", newBookTitle: "ספר חדש", newBookBody: "בחרו ספר חדש — מהאוסף הנבחר או מכל הספרייה.", pileKeepsTitle: "הערימה נשארת", pileKeepsBody: "המילים שנאספו נשארות כשעוברים בין עמודים וספרים.", credit: "בעקבות „גניבת מילים מספר” של ג׳ף טווידי, How to Write One Song ‏(2020)", buildTitle: "בנייה", buildBody: "עכשיו הערימה שלך לעיצוב. גררו את המילים לסדר חדש, פצלו ביטוי בחזרה למילים בודדות או לחצו על מילה כדי לערוך אותה — שנו זמן, החליפו שם — עד שהשורות מתחילות לשיר.", looseFragments: "מקטעים חופשיים", looseExample: "אור הנמל\nענה\nנמוך", worthKeeping: "…לשורה שכדאי לשמור", revisedExample: "אור הנמל בער נמוך\nואיש לא ענה", reorderTitle: "סידור מחדש", reorderBody: "גררו מילים לצירופים חדשים.", splitTitle: "פיצול", splitBody: "פרקו ביטוי למילים בודדות.", saveTitle: "שמירה", saveBody: "שלחו את הטיוטה לפנקס המילים כעמוד." },
